Here's a complete implementation:

**XAML — wrap `CollectionView` in `RefreshView` for pull-to-refresh:**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemListPage"
             x:DataType="vm:ItemListViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}"
                        EmptyView="No items found.">
            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}" FontSize="12"
                                   TextColor="{StaticResource Gray500}" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel — using CommunityToolkit.Mvvm:**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemListViewModel : ObservableObject
{
    private readonly IItemService _itemService;

    public ItemListViewModel(IItemService itemService)
    {
        _itemService = itemService;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync($"detail?id={CurrentItem.Id}");

        // Clear selection so the user can re-select the same item later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var freshData = await _itemService.GetItemsAsync();
            Items.Clear();
            foreach (var item in freshData)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;   // Must set false to hide the spinner
        }
    }
}
```

**Key binding summary:**

| Property | Binds to | Purpose |
|---|---|---|
| `ItemsSource` | `ObservableCollection<Item>` | Auto-updates UI on add/remove |
| `SelectedItem` (TwoWay) | `CurrentItem` | Tracks selected item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Navigates to detail page |
| `RefreshView.Command` | `RefreshCommand` | Reloads data from API |
| `RefreshView.IsRefreshing` | `IsRefreshing` | Controls spinner visibility |

**Important details:**
- Set `IsRefreshing = false` in a `finally` block — otherwise the spinner never stops.
- Reset `CurrentItem = null` after navigating so the same item can be re-selected.
- Use `ObservableCollection<T>`, not `List<T>`, so the UI reacts to collection changes.
- `x:DataType` on both the page and `DataTemplate` enables compiled bindings.
- `MeasureFirstItem` improves scroll performance for uniform-height rows.
